export interface BatchSplitEntry {
  name: string;
  description: string;
}

function extractJsonArrayText(raw: string): string | null {
  const jsonMatch = raw.match(/\[[\s\S]*\]/);
  return jsonMatch ? jsonMatch[0] : null;
}

function extractJsonObjectText(raw: string): string | null {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  return jsonMatch ? jsonMatch[0] : null;
}

export function parseBatchSplitEntries(splitResponse: string): BatchSplitEntry[] {
  const jsonText = extractJsonArrayText(splitResponse);
  if (!jsonText) {
    return [];
  }

  const parsed = JSON.parse(jsonText);
  if (!Array.isArray(parsed)) {
    return [];
  }

  return parsed
    .map(item => ({
      name: String(item?.name ?? '').trim(),
      description: String(item?.description ?? '').trim(),
    }))
    .filter(item => item.name.length > 0 && item.description.length > 0);
}

export function buildBatchWorldbookEntryFromResponse(
  response: string,
  fallbackEntry: BatchSplitEntry,
  index: number,
): Record<string, any> | null {
  const jsonText = extractJsonObjectText(response);
  if (!jsonText) {
    return null;
  }

  const aiResult = JSON.parse(jsonText);

  return {
    name: aiResult.name || fallbackEntry.name,
    enabled: true,
    strategy: {
      type: 'conditional' as const,
      keys: aiResult.key || [fallbackEntry.name],
      keys_secondary: { logic: 'and_any' as const, keys: [] },
      scan_depth: 'same_as_global' as const,
    },
    position: {
      type: 'after_character_definition' as const,
      role: 'system' as const,
      depth: 0,
    },
    content: aiResult.content || fallbackEntry.description,
    comment: aiResult.comment || '',
    insertion_order: index + 1,
    case_sensitive: false,
    exclude_recursion: true,
    uid: Date.now() + index,
  };
}
