export interface NpcBatchRequestOptions {
  model: string;
  maxTokens: number;
  systemPrompt: string;
  description: string;
  generatedResults: string[];
  index: number;
}

function getNpcNamePreview(content: string): string {
  const firstLine = content
    .split('\n')
    .map(line => line.trim())
    .find(line => line.length > 0);

  return firstLine || '未命名';
}

function getGeneratedNpcNames(results: string[]): string {
  if (results.length === 0) {
    return '无';
  }

  return results.map(getNpcNamePreview).join('、');
}

export function buildNpcBatchRequestPayload(options: NpcBatchRequestOptions): Record<string, any> {
  const { model, maxTokens, systemPrompt, description, generatedResults, index } = options;

  return {
    model,
    max_tokens: maxTokens,
    temperature: 0.9,
    stream: false,
    messages: [
      {
        role: 'system',
        content: `${systemPrompt}\n\n注意：每次生成的 NPC 要有独特性，不要重复。`,
      },
      {
        role: 'user',
        content: `请为以下描述生成第 ${index + 1} 个独特的 NPC 设定：\n${description}\n\n已生成的 NPC 名字：${getGeneratedNpcNames(generatedResults)}`,
      },
    ],
  };
}

export function buildNpcWorldbookEntries(contents: string[]): Array<Record<string, any>> {
  const timestamp = new Date().toLocaleString();

  return contents.map((content, idx) => ({
    content,
    comment: `NPC ${idx + 1} - ${timestamp}`,
    keys: ['NPC', '配角'],
    enabled: true,
  }));
}
